    {
        if (DatabaseDescriptor.getAuditLoggingOptions().enabled)
            registerAsListener();
    }


public BinAuditLogger(Map<String, String> params)
    {
        AuditLogOptions auditLoggingOptions = DatabaseDescriptor.getAuditLoggingOptions();

